 Begin CmpMap 	# Compound Mapping
    Nin = 2 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    MapA = 	# First component Mapping
       Begin WinMap 	# Map one window on to another
          Nin = 2 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          Sft1 = 5 	# Shift for axis 1
          Scl1 = 2 	# Scale factor for axis 1
          Sft2 = -3 	# Shift for axis 2
          Scl2 = 4 	# Scale factor for axis 2
       End WinMap
    MapB = 	# Second component Mapping
       Begin MatrixMap 	# Matrix transformation
          Nin = 2 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          M0 = 3 	# Forward matrix value
          M1 = 5 	# Forward matrix value
          IM0 = 0.33333333333333331 	# Inverse matrix value
          IM1 = 0.20000000000000001 	# Inverse matrix value
          Form = "Diagonal" 	# Matrix storage form
       End MatrixMap
 End CmpMap
